1	<script>
2		let angle = $state(90);
3		let dragging = false;
4		let svgEl;
5	
6		const candidates = [
7			{ id: 'c1', deg: 20 },
8			{ id: 'c2', deg: 70 },
9			{ id: 'c3', deg: 110 },
10			{ id: 'c4', deg: 160 }
11		];
12	
13		function toPoint(deg, r, cx = 200, cy = 200) {
14			const rad = (deg * Math.PI) / 180;
15			return { x: cx + r * Math.cos(rad), y: cy - r * Math.sin(rad) };
16		}
17	
18		const scores = $derived(
19			candidates.map((c) => {
20				const diff = ((angle - c.deg) * Math.PI) / 180;
21				return Math.round(100 * Math.cos(diff));
22			})
23		);
24	
25		const bestIndex = $derived(
26			scores.reduce((best, s, i) => (s > scores[best] ? i : best), 0)
27		);
28	
29		function angleFromClient(clientX, clientY) {
30			const rect = svgEl.getBoundingClientRect();
31			const cx = rect.left + rect.width / 2;
32			const cy = rect.top + rect.height / 2;
33			const dx = clientX - cx;
34			const dy = clientY - cy;
35			let a = (Math.atan2(-dy, dx) * 180) / Math.PI;
36			if (a < 0) a += 360;
37			return Math.round(a);
38		}
39	
40		function handlePointerDown(e) {
41			dragging = true;
42			svgEl.setPointerCapture(e.pointerId);
43			angle = angleFromClient(e.clientX, e.clientY);
44		}
45	
46		function handlePointerMove(e) {
47			if (!dragging) return;
48			angle = angleFromClient(e.clientX, e.clientY);
49		}
50	
51		function handlePointerUp(e) {
52			dragging = false;
53			try {
54				svgEl.releasePointerCapture(e.pointerId);
55			} catch (err) {
56				// already released, ignore
57			}
58		}
59	
60		function handleKeydown(e) {
61			let handled = true;
62			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') {
63				angle = Math.min(360, angle + 5);
64			} else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') {
65				angle = Math.max(0, angle - 5);
66			} else if (e.key === 'Home') {
67				angle = 0;
68			} else if (e.key === 'End') {
69				angle = 360;
70			} else {
71				handled = false;
72			}
73			if (handled) e.preventDefault();
74		}
75	
76		function fmt(n) {
77			return n > 0 ? `+${n}` : `${n}`;
78		}
79	
80		const probeTip = $derived(toPoint(angle, 160));
81		const probeLabel = $derived.by(() => {
82			const rad = (angle * Math.PI) / 180;
83			const shaftR = 80;
84			const sideOffset = 22;
85			return {
86				x: 200 + shaftR * Math.cos(rad) - sideOffset * Math.sin(rad),
87				y: 200 - shaftR * Math.sin(rad) - sideOffset * Math.cos(rad)
88			};
89		});
90	</script>
91	
92	<div data-interactive="dot-alignment" class="wrap">
93		<p class="instruction">Turn the probe (drag it or use arrow keys) until a bar peaks.</p>
94	
95		<div class="stage">
96			<svg
97				bind:this={svgEl}
98				class="dial"
99				viewBox="0 0 400 400"
100				role="slider"
101				tabindex="0"
102				aria-label="Probe angle in degrees"
103				aria-valuemin="0"
104				aria-valuemax="360"
105				aria-valuenow={angle}
106				aria-valuetext={`${angle} degrees`}
107				onpointerdown={handlePointerDown}
108				onpointermove={handlePointerMove}
109				onpointerup={handlePointerUp}
110				onpointercancel={handlePointerUp}
111				onkeydown={handleKeydown}
112			>
113				<defs>
114					<marker id="head-probe" markerWidth="10" markerHeight="10" refX="6" refY="5" orient="auto">
115						<path d="M0,0 L10,5 L0,10 Z" style="fill: var(--data-heat)" />
116					</marker>
117					<marker id="head-candidate" markerWidth="9" markerHeight="9" refX="5" refY="4.5" orient="auto">
118						<path d="M0,0 L9,4.5 L0,9 Z" style="fill: var(--data-observed)" />
119					</marker>
120				</defs>
121	
122				<circle cx="200" cy="200" r="160" fill="none" stroke="var(--color-text)" stroke-width="1" opacity="0.12" />
123				<circle cx="200" cy="200" r="4" fill="var(--color-text)" opacity="0.3" />
124	
125				{#each candidates as c, i}
126					{@const tip = toPoint(c.deg, 140)}
127					{@const lbl = toPoint(c.deg, 168)}
128					<line
129						x1="200"
130						y1="200"
131						x2={tip.x}
132						y2={tip.y}
133						stroke="var(--data-observed)"
134						stroke-width="3"
135						opacity={i === bestIndex ? 0.85 : 0.4}
136						marker-end="url(#head-candidate)"
137					/>
138					<text
139						x={lbl.x}
140						y={lbl.y}
141						text-anchor="middle"
142						dominant-baseline="middle"
143						class="tip-label"
144						style="fill: var(--color-text)"
145					>{c.id}</text>
146				{/each}
147	
148				<line
149					x1="200"
150					y1="200"
151					x2={probeTip.x}
152					y2={probeTip.y}
153					stroke="var(--data-heat)"
154					stroke-width="6"
155					marker-end="url(#head-probe)"
156				/>
157				<text
158					x={probeLabel.x}
159					y={probeLabel.y}
160					text-anchor="middle"
161					dominant-baseline="middle"
162					class="probe-label"
163					style="fill: var(--color-text)"
164				>probe {angle}°</text>
165			</svg>
166		</div>
167	
168		<div class="scores">
169			{#each candidates as c, i}
170				<div class="score-col" class:leading={i === bestIndex}>
171					<div class="score-name" style="color: var(--color-text)">{c.id}</div>
172					<div class="bar-track">
173						<div class="zero-line"></div>
174						{#if scores[i] >= 0}
175							<div class="bar pos" style="height: {Math.abs(scores[i]) * 0.55}px; opacity: {i === bestIndex ? 1 : 0.45}"></div>
176						{:else}
177							<div class="bar neg" style="height: {Math.abs(scores[i]) * 0.55}px; opacity: {i === bestIndex ? 1 : 0.45}"></div>
178						{/if}
179					</div>
180					<div class="score-num">{fmt(scores[i])}</div>
181				</div>
182			{/each}
183		</div>
184	</div>
185	
186	<style>
187		.wrap {
188			display: flex;
189			flex-direction: column;
190			align-items: center;
191			gap: clamp(0.75rem, 2.5vw, 1.25rem);
192			width: 100%;
193			max-width: 640px;
